from typing import List

def solve(words: List[str]) -> List[int]:
    n = len(words)
    if n == 1:
        return [0]

    answer = []

    for i in range(n):
        # Create a new list without the i-th element
        new_words = words[:i] + words[i+1:]
        max_len = 0

        # Iterate through adjacent pairs in new_words
        for j in range(len(new_words) - 1):
            a, b = new_words[j], new_words[j+1]
            current_len = 0
            min_len = min(len(a), len(b))
            # Calculate the common prefix length
            for k in range(min_len):
                if a[k] == b[k]:
                    current_len += 1
                else:
                    break
            if current_len > max_len:
                max_len = current_len
                # Early exit if max possible is found (all characters match)
                if max_len == min_len:
                    break

        answer.append(max_len)

    return answer
